#include <stdio.h>
#include <stdlib.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int *arr = malloc(2 * sizeof(int));
    if (!arr) return 1;
    arr[0] = 10; arr[1] = 20;
    printf("Initial: %d %d\n", arr[0], arr[1]);
    // ★ Pattern safe : variable temporaire
    int *tmp = realloc(arr, 6 * sizeof(int));
    if (!tmp) { free(arr); return 1; } // ★ arr toujours valide si NULL
    arr = tmp; // ★ réassigner seulement si succès
    arr[2] = 30; arr[3] = 40; arr[4] = 50; arr[5] = 60;
    for (int i = 0; i < 6; i++) printf("%d ", arr[i]);
    printf("\n");
    free(arr);
    return 0;
}

